router6.get("/", async (req2, res) => {
  try {
    const { category, search } = req2.query;
    let whereClause = {
      active: true
      // Seulement les icônes actives
    };
    if (category && category !== "all") {
      whereClause.category = category;
    }
    if (search && typeof search === "string") {
      const searchTerm = search.toLowerCase();
      whereClause.OR = [
        { name: { contains: searchTerm, mode: "insensitive" } },
        { description: { contains: searchTerm, mode: "insensitive" } },
        { tags: { hasSome: [searchTerm] } }
      ];
    }
    const icons = await prisma6.icon.findMany({
      where: whereClause,
      orderBy: [
        { category: "asc" },
        { name: "asc" }
      ]
    });
    const groupedIcons = icons.reduce((acc, icon) => {
      if (!acc[icon.category]) {
        acc[icon.category] = [];
      }
      acc[icon.category].push(icon);
      return acc;
    }, {});
    res.json({
      success: true,
      data: {
        icons,
        groupedIcons,
        totalCount: icons.length,
        categories: Object.keys(groupedIcons).sort()
      }
    });
  } catch (error) {
    logger.error("[ICONS-API] Erreur lors de la r\xE9cup\xE9ration des ic\xF4nes:", error);
    res.status(500).json({
      success: false,
      error: "Erreur lors de la r\xE9cup\xE9ration des ic\xF4nes",
      details: error.message
    });
  }
});
