async function getProductDocumentsForDevis(organizationId, tblData) {
  if (!tblData || Object.keys(tblData).length === 0) return [];
  const formValues = [];
  for (const [key2, value] of Object.entries(tblData)) {
    if (key2.startsWith("__")) continue;
    if (typeof value === "string" && value.trim()) {
      formValues.push(value.trim());
    }
  }
  if (formValues.length === 0) return [];
  const allDocs = await prisma9.productDocument.findMany({
    where: { organizationId },
    include: {
      tableRow: true,
      node: { select: { label: true } }
    }
  });
  if (allDocs.length === 0) {
    return [];
  }
  const matchedDocs = /* @__PURE__ */ new Map();
  for (const doc of allDocs) {
    if (!doc.tableRow) continue;
    let cells = [];
    try {
      const raw = doc.tableRow.cells;
      if (Array.isArray(raw)) {
        cells = raw.map((c) => String(c).trim());
      } else if (typeof raw === "string") {
        try {
          const parsed = JSON.parse(raw);
          cells = Array.isArray(parsed) ? parsed.map((c) => String(c).trim()) : [raw.trim()];
        } catch {
          cells = raw.split(",").map((c) => c.trim());
        }
      }
    } catch {
      continue;
    }
    for (const formVal of formValues) {
      const matched = cells.some((cell) => cell === formVal);
      if (matched) {
        const fileKey = doc.driveFileId || doc.id;
        if (!matchedDocs.has(fileKey)) {
          matchedDocs.set(fileKey, doc);
        }
        break;
      }
    }
  }
  return Array.from(matchedDocs.values()).map((doc) => ({
    id: doc.id,
    name: doc.name,
    fileName: doc.fileName,
    mimeType: doc.mimeType,
    storageType: doc.storageType,
    driveFileId: doc.driveFileId,
    localPath: doc.localPath,
    externalUrl: doc.externalUrl,
    category: doc.category,
    nodeLabel: doc.node?.label
  }));
}
