// src/services/ai-moderation.ts
var import_generative_ai2 = require("@google/generative-ai");
init_logger();
var genAI = new import_generative_ai2.GoogleGenerativeAI(process.env.GEMINI_API_KEY || process.env.GOOGLE_AI_API_KEY || "");
var DEFAULT_BANNED = [
  "hate_speech",
  "harassment",
  "sexual_content",
  "violence",
  "self_harm",
  "illegal"
];
async function moderateContent(content, settings) {
  if (!settings.moderationMode || settings.moderationMode === "disabled" || settings.moderationMode === "manual") {
    return { flagged: false, categories: [], confidence: 0, reason: "" };
  }
  if (!content || content.trim().length < 3) {
    return { flagged: false, categories: [], confidence: 0, reason: "" };
  }
  const bannedCategories = Array.isArray(settings.aiBannedCategories) ? settings.aiBannedCategories : DEFAULT_BANNED;
  try {
    const model = genAI.getGenerativeModel({ model: "gemini-pro" });
    const prompt = `Tu es un mod\xE9rateur de contenu pour une plateforme professionnelle (r\xE9seau d'entreprise). Analyse le texte suivant et d\xE9termine s'il contient du contenu inappropri\xE9.

Cat\xE9gories \xE0 d\xE9tecter : ${bannedCategories.join(", ")}

Texte \xE0 analyser :
"""
${content.substring(0, 2e3)}
"""

R\xE9ponds UNIQUEMENT en JSON valide (pas de markdown, pas de backticks) :
{"flagged": boolean, "categories": ["category1"], "confidence": 0.0-1.0, "reason": "explication courte en fran\xE7ais"}

Si le contenu est acceptable, retourne : {"flagged": false, "categories": [], "confidence": 0.0, "reason": ""}`;
    const result = await model.generateContent(prompt);
    const response = result.response;
    const text = response.text().trim();
    const jsonStr = text.replace(/```json\s*/g, "").replace(/```\s*/g, "").trim();
    const parsed = JSON.parse(jsonStr);
    return {
      flagged: !!parsed.flagged,
      categories: Array.isArray(parsed.categories) ? parsed.categories : [],
      confidence: typeof parsed.confidence === "number" ? parsed.confidence : 0.5,
      reason: parsed.reason || "",
      aiRaw: text
    };
  } catch (error) {
    logger.error("[AI-Moderation] Error:", error);
    return {
      flagged: false,
      categories: [],
      confidence: 0,
      reason: "AI moderation unavailable"
    };
  }
}

