router79.get("/feed", authenticateToken, async (req2, res) => {
  try {
    const user = req2.user;
    const orgId = user.organizationId || req2.headers["x-organization-id"];
    const {
      visibility,
      category,
      targetLeadId,
      cursor,
      limit = "20",
      mode
      // 'personal' | 'org' — pour les users avec org qui veulent filtrer
    } = req2.query;
    const take = Math.min(parseInt(limit) || 20, 50);
    const feedMode = mode === "personal" ? "personal" : mode === "public" ? "public" : "org";
    const isSuperAdmin2 = user.role === "super_admin" || user.isSuperAdmin;
    const socialCtx = await getSocialContext(user.id, orgId, isSuperAdmin2);
    let where;
    if (user.role === "client") {
      where = {
        isPublished: true,
        OR: [
          { visibility: "IN", organizationId: orgId },
          { visibility: "ALL" },
          { visibility: "CLIENT", targetLeadId: user.linkedLeadId }
        ]
      };
    } else if (visibility) {
      where = { isPublished: true, visibility };
      if (orgId) where.organizationId = orgId;
    } else {
      where = buildWallFeedWhere(socialCtx, feedMode);
    }
    if (category) where.category = category;
    if (targetLeadId) where.targetLeadId = targetLeadId;
    if (cursor) where.createdAt = { lt: new Date(cursor) };
    const posts = await db.wallPost.findMany({
      where,
      orderBy: [
        { isPinned: "desc" },
        { createdAt: "desc" }
      ],
      take,
      include: {
        author: {
          select: { id: true, firstName: true, lastName: true, avatarUrl: true, role: true }
        },
        organization: {
          select: { id: true, name: true, logoUrl: true }
        },
        targetLead: {
          select: { id: true, firstName: true, lastName: true, company: true }
        },
        parentPost: {
          include: {
            author: { select: { id: true, firstName: true, lastName: true, avatarUrl: true } },
            organization: { select: { id: true, name: true, logoUrl: true } }
          }
        },
        reactions: {
          select: { id: true, userId: true, type: true }
        },
        comments: {
          orderBy: { createdAt: "asc" },
          take: 3,
          include: {
            author: {
              select: { id: true, firstName: true, lastName: true, avatarUrl: true, role: true }
            }
          }
        },
        _count: {
          select: { comments: true, reactions: true, shares: true }
        }
      }
    });
    const enriched = posts.map((post) => ({
      ...post,
      myReaction: post.reactions.find((r) => r.userId === user.id) || null,
      totalComments: post._count.comments,
      totalReactions: post._count.reactions,
      totalShares: post._count.shares
    }));
    res.json({
      posts: enriched,
      nextCursor: posts.length === take ? posts[posts.length - 1].createdAt.toISOString() : null
    });
  } catch (error) {
    logger.error("[WALL] Erreur feed:", error);
    res.status(500).json({ error: "Erreur lors du chargement du fil" });
  }
});
