  const hauteur_cm = avgHeightMm * scaleFactor / 10;
  const incertitude_largeur_cm = avgWidthUncertaintyMm * scaleFactor / 10;
  const incertitude_hauteur_cm = avgHeightUncertaintyMm * scaleFactor / 10;
