router116.post("/retry/:invoiceId", authenticateToken, isAdmin, async (req2, res) => {
  const { invoiceId } = req2.params;
  try {
    const organizationId = getOrganizationId2(req2);
    if (!organizationId) {
      return res.status(400).json({ success: false, message: "ID d'organisation requis" });
    }
    const config = await db.peppolConfig.findUnique({ where: { organizationId } });
    if (!config?.enabled || config.registrationStatus !== "ACTIVE") {
      return res.status(400).json({ success: false, message: "Peppol n'est pas activ\xE9" });
    }
    let invoiceSource = "standalone";
    let invoice = null;
    const chantierInv = await db.chantierInvoice.findFirst({
      where: { id: invoiceId, organizationId },
      select: { id: true, peppolStatus: true, peppolOdooInvoiceId: true, invoiceNumber: true }
    });
    if (chantierInv) {
      invoiceSource = "chantier";
      invoice = chantierInv;
    } else {
      const standaloneInv = await db.standaloneInvoice.findFirst({
        where: { id: invoiceId, organizationId },
        select: { id: true, peppolStatus: true, peppolOdooInvoiceId: true, invoiceNumber: true }
      });
      if (standaloneInv) {
        invoiceSource = "standalone";
        invoice = standaloneInv;
      }
    }
    if (!invoice) {
      return res.status(404).json({ success: false, message: "Facture non trouv\xE9e" });
    }
    if (!["PROCESSING", "ERROR"].includes(invoice.peppolStatus || "")) {
      return res.status(400).json({
        success: false,
        message: `Impossible de r\xE9essayer : statut actuel "${invoice.peppolStatus}"`
      });
    }
    if (!invoice.peppolOdooInvoiceId) {
      return res.status(400).json({
        success: false,
        message: "Pas d'ID Odoo enregistr\xE9 pour cette facture. Renvoyez-la via le bouton Peppol standard."
      });
    }
    const bridge = getPeppolBridge();
    const odooInvoiceData = await bridge.call("account.move", "read", [
      [invoice.peppolOdooInvoiceId]
    ], { fields: ["peppol_move_state", "peppol_message_uuid", "state"] });
    if (!odooInvoiceData?.length) {
      return res.status(400).json({ success: false, message: "Facture non trouv\xE9e dans Odoo" });
    }
    const odooState = odooInvoiceData[0].peppol_move_state;
    if (odooState === "done") {
      const updateData = {
        peppolStatus: "SENT",
        peppolMessageId: odooInvoiceData[0].peppol_message_uuid || invoice.id,
        peppolError: null
      };
      if (invoiceSource === "chantier") {
        await db.chantierInvoice.update({ where: { id: invoiceId }, data: { ...updateData, updatedAt: /* @__PURE__ */ new Date() } });
      } else {
        await db.standaloneInvoice.update({ where: { id: invoiceId }, data: updateData });
      }
      return res.json({ success: true, data: { peppolStatus: "SENT", message: "Facture d\xE9j\xE0 livr\xE9e dans Odoo !" } });
    }
    const wizardSuccess = await bridge.sendViaWizard(invoice.peppolOdooInvoiceId, config.odooCompanyId);
    if (!wizardSuccess) {
      logger.warn(`[Peppol] Retry wizard partiel pour invoice ${invoiceId}`);
    }
    const retryData = {
      peppolStatus: "PROCESSING",
      peppolSentAt: /* @__PURE__ */ new Date(),
      peppolRetryCount: 0,
      peppolError: "Retry lanc\xE9 manuellement"
    };
    if (invoiceSource === "chantier") {
      await db.chantierInvoice.update({ where: { id: invoiceId }, data: { ...retryData, updatedAt: /* @__PURE__ */ new Date() } });
    } else {
      await db.standaloneInvoice.update({ where: { id: invoiceId }, data: retryData });
    }
    res.json({
      success: true,
      data: {
        peppolStatus: "PROCESSING",
        message: "Envoi Peppol relanc\xE9. Le cron v\xE9rifiera le statut toutes les 2 minutes."
      }
    });
  } catch (error) {
    logger.error("[Peppol] Erreur POST /retry/:invoiceId:", error);
    res.status(500).json({ success: false, message: `Erreur de retry: ${error.message}` });
  }
});
